    _satc_polygon_reset_calc_points(polygon, num_points);
    _satc_polygon_reset_edges(polygon, num_points);
    _satc_polygon_reset_normals(polygon, num_points);
  }
  _satc_polygon_copy_points(polygon, num_points, points);
  return polygon;
